import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

const API = "http://192.168.7.12:5000/api";

/* Fingerprint Gate */
function FingerprintGate({ onVerified }) {
  const [loading, setLoading] = useState(false);

  const handleClick = () => {
    setLoading(true);
    setTimeout(() => {
      onVerified("test-device");
    }, 1000);
  };

  return (
    <div style={{
      position: 'fixed', inset: 0, zIndex: 999,
      background: '#0f172a',
      display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center'
    }}>
      <h2 style={{ color: 'white', marginBottom: 20 }}>
        🔐 Verify to View Emergency Info
      </h2>

      <button onClick={handleClick} style={{
        background: '#ef4444',
        color: 'white',
        border: 'none',
        padding: '15px 25px',
        borderRadius: 10,
        cursor: 'pointer'
      }}>
        {loading ? "Verifying..." : "Verify & View"}
      </button>
    </div>
  );
}

/* MAIN PAGE */
export default function ScanPage() {
  const { token } = useParams();

  const [data, setData] = useState(null);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [verified, setVerified] = useState(false);

  const handleVerified = async () => {
    setVerified(true);
    setLoading(true);

    try {
      const res = await axios.get(`${API}/public/scan/${token}`);
      setData(res.data);
    } catch (err) {
      setError("Failed to load emergency information");
    } finally {
      setLoading(false);
    }
  };

  const callContact = (contact) => {
    window.location.href = `tel:${contact.phone}`;
  };

  return (
    <>
      {!verified && <FingerprintGate onVerified={handleVerified} />}

      <div style={{
        minHeight: '100vh',
        background: '#0f172a',
        color: 'white',
        padding: 20
      }}>

        <h1 style={{ textAlign: 'center', color: '#ef4444' }}>
          🚨 Emergency Info
        </h1>

        {loading && <h3 style={{ textAlign: 'center' }}>Loading...</h3>}

        {error && <h3 style={{ textAlign: 'center', color: 'red' }}>{error}</h3>}

        {/* SAFE DATA RENDER */}
        {data && data.profile && (
          <div style={{ marginTop: 20 }}>

            {/* Profile */}
            <div style={{
              background: '#1e293b',
              padding: 20,
              borderRadius: 10,
              marginBottom: 20
            }}>
              <h2>{data?.profile?.full_name || "No Name"}</h2>

              {data?.profile?.gender && <p>👤 {data.profile.gender}</p>}

              {data?.profile?.date_of_birth && (
                <p>🎂 {new Date(data.profile.date_of_birth).toLocaleDateString()}</p>
              )}

              {data?.profile?.blood_type && (
                <p>🩸 {data.profile.blood_type}</p>
              )}
            </div>

            {/* Medical */}
            <div style={{
              background: '#1e293b',
              padding: 20,
              borderRadius: 10,
              marginBottom: 20
            }}>
              <h3>🏥 Medical Info</h3>

              <p>⚠️ {data?.profile?.allergies || "None"}</p>
              <p>🩺 {data?.profile?.medical_conditions || "None"}</p>
              <p>💊 {data?.profile?.current_medications || "None"}</p>
            </div>

            {/* Contacts */}
            {data?.contacts && data.contacts.length > 0 && (
              <div style={{
                background: '#1e293b',
                padding: 20,
                borderRadius: 10
              }}>
                <h3>📞 Emergency Contacts</h3>

                {data.contacts.map((c) => (
                  <div key={c.id} style={{ marginTop: 10 }}>
                    <p>{c.name} ({c.relationship})</p>

                    <button
                      onClick={() => callContact(c)}
                      style={{
                        background: '#ef4444',
                        border: 'none',
                        color: 'white',
                        padding: '10px 15px',
                        borderRadius: 8,
                        cursor: 'pointer'
                      }}
                    >
                      📞 Call
                    </button>
                  </div>
                ))}
              </div>
            )}

          </div>
        )}
      </div>
    </>
  );
}
